    // ========== STATE VARIABLES ==========

    uint256 private _tokenIds;

    /// @notice Tracks the last timestamp a user opened a daily pack
    mapping(address => uint256) public lastOpenedTimestamp;

    /// @dev A mapping from tokenId => CardMetadata (on-chain storage of attributes)
    mapping(uint256 => CardMetadata) public cardMetadata;

    // ========== DATA STRUCTURES ==========

    enum Rarity {
        Common,
        Uncommon,
        Rare,
        DoubleRare,
        UltraRare,
        SecretRare
    }

    /**
     * @dev Struct to hold important Pokémon card attributes.
     *      This is just an example; adapt fields to your app's needs.
     */
    struct CardMetadata {
        string name; // e.g. "Charizard"
        uint8 cardType; // e.g. "Fire"
        Rarity rarity; // 0: Common, 1: Uncommon, 2: Rare, 3: Double Rare, 4: Ultra Rare, 5: Secret Rare
        string cardDetailURL; // Image, weakness, resistance, ability, attack
        uint256 hp; // e.g. 330
    }

    // ========== EVENTS ==========

    /// @dev Emitted when a new card is minted
    event CardMinted(
        uint256 indexed tokenId,
        address indexed owner,
        Rarity rarity,
        uint8 cardType,
        uint256 hp,
        string name
    );

    event Deployed(address indexed addr);

    // ========== CONSTRUCTOR ==========

    /**
     * @param _name   Collection name (e.g. "PokemonTCGCollection")
     * @param _symbol Collection symbol (e.g. "PKMN")
     */
    constructor(
        string memory _name,
        string memory _symbol
    ) ERC721(_name, _symbol) {
        // Grant the deployer the default admin role and the minter role
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);

        emit Deployed(address(this));
    }

    // ========== EXTERNAL / PUBLIC FUNCTIONS ==========

    /**
     * @notice Allows an authorized minter to mint special (rare) Pokémon cards.
     *         Useful for promotional events, giveaways, or manual minting.
     * @param to      The address that will receive the NFT
