     */
    function mintRareCard(
        address to,
        CardMetadata calldata data,
        string calldata tokenURI_
    ) external onlyRole(MINTER_ROLE) nonReentrant {
        _tokenIds++;
        uint256 newTokenId = _tokenIds;

        // Mint the token
        _safeMint(to, newTokenId);
        // Store the card metadata on-chain
        cardMetadata[newTokenId] = data;
        // If you have a URI (e.g. IPFS metadata file), you can set it here
        _setTokenURI(newTokenId, tokenURI_);

        emit CardMinted(
            newTokenId,
            to,
            data.rarity,
            data.cardType,
            data.hp,
            data.name
        );
    }

