import { createConfig, configureChains } from 'wagmi'
import { mainnet, sepolia } from 'wagmi/chains'
import { publicProvider } from 'wagmi/providers/public'
// If using RainbowKit, you’d import from '@rainbow-me/rainbowkit':
// import { getDefaultWallets, RainbowKitProvider } from '@rainbow-me/rainbowkit'

const { chains, publicClient } = configureChains(
  [mainnet, sepolia], // choose your chain(s)
  [publicProvider()]
)

// If you want default RainbowKit wallets:
//// const { connectors } = getDefaultWallets({
////   appName: 'Pokemon DeFi',
////   chains
//// })

// If you want minimal wagmi connectors:
import { InjectedConnector } from 'wagmi/connectors/injected'
const connectors = [
  new InjectedConnector({
    chains,
    options: { name: 'Injected' },
  }),
]

export const wagmiConfig = createConfig({
  autoConnect: true,
  connectors,
  publicClient, 
})

--------------------------------------------------------------------------------
5) Wrap Your App in a Wagmi/Rainbow Provider
--------------------------------------------------------------------------------
You can wrap the entire app in the “providers” using Next.js layout or 
a custom Providers component. For minimal wagmi usage:

app/providers.tsx:
--------------------------------------------------------------------------------
'use client'

import { WagmiConfig } from 'wagmi'
import { wagmiConfig } from '@/lib/wagmi'

// If you use RainbowKit, import <RainbowKitProvider> here as well

export function Providers({ children }: { children: React.ReactNode }) {
  return (
    <WagmiConfig config={wagmiConfig}>
      {children}
    </WagmiConfig>
  )
}

Then import and use it in your layout.tsx:

