ABI, contract address, and function arguments with your actual values.

app/mint/page.tsx:
--------------------------------------------------------------------------------
'use client'

import { useState } from 'react'
import { useAccount, useContractWrite, usePrepareContractWrite } from 'wagmi'

// Example: import your contract’s ABI
import PokemonNFTAbi from '@/lib/abis/PokemonNFT.json' assert { type: 'json' }

const POKEMON_NFT_ADDRESS = '0xYourDeployedContractAddress' // replace

export default function MintPage() {
  const { address } = useAccount()

  const [name, setName] = useState('')
  const [hp, setHp] = useState(100)
  const [cardType, setCardType] = useState(0)  // e.g. Fire=0, Water=1, ...
  const [rarity, setRarity] = useState(0)      // enum Rarity index
  const [cardDetailURL, setCardDetailURL] = useState('')

  // Prepare the contract call
  const { config } = usePrepareContractWrite({
    address: POKEMON_NFT_ADDRESS,
    abi: PokemonNFTAbi,
    functionName: 'mintRareCard',
    args: [
      address, 
      {
        name,
        cardType,
        rarity, 
        cardDetailURL,
        hp
      },
      '' // tokenURI string if you want to pass an external URI
    ],
  })

  // Actually execute
  const { data, isLoading, isSuccess, write } = useContractWrite(config)

  return (
    <section>
      <h1 className="text-2xl font-bold mb-4">Admin Mint</h1>

      <div className="space-y-2 mb-4">
        <div>
          <label>Name:</label>
          <input
            type="text"
            className="border p-1 ml-2"
            value={name}
            onChange={(e) => setName(e.target.value)}
          />
        </div>
        <div>
          <label>HP:</label>
          <input
            type="number"
            className="border p-1 ml-2"
            value={hp}
            onChange={(e) => setHp(Number(e.target.value))}
          />
        </div>
        <div>
          <label>Card Type (enum index):</label>
          <input
            type="number"
            className="border p-1 ml-2"
            value={cardType}
            onChange={(e) => setCardType(Number(e.target.value))}
          />
        </div>
        <div>
          <label>Rarity (enum index):</label>
          <input
            type="number"
            className="border p-1 ml-2"
            value={rarity}
            onChange={(e) => setRarity(Number(e.target.value))}
          />
        </div>
        <div>
          <label>Card Detail URL:</label>
          <input
            type="text"
            className="border p-1 ml-2"
            value={cardDetailURL}
            onChange={(e) => setCardDetailURL(e.target.value)}
          />
        </div>
      </div>

      <button
        onClick={() => write?.()}
        disabled={!write}
        className="bg-green-600 text-white px-4 py-2 rounded"
      >
        {isLoading ? 'Minting...' : 'Mint'}
      </button>

      {isSuccess && (
        <div className="mt-4 text-green-600">
          Success! Check your wallet for the new NFT.
        </div>
      )}
    </section>
  )
}

