8) Marketplace Page
--------------------------------------------------------------------------------
We’ll need two main functions here: listCard(tokenId, price) and buyCard(tokenId).  
Below is a simplified approach where you input a tokenId & price to list, and a tokenId to buy.  
In reality, you’ll likely fetch a list of active listings from an index or subgraph, then map them in the UI.

app/marketplace/page.tsx:
--------------------------------------------------------------------------------
'use client'

import { useState } from 'react'
import { useContractWrite, usePrepareContractWrite } from 'wagmi'
import MarketplaceAbi from '@/lib/abis/Marketplace.json' assert { type: 'json' }

const MARKETPLACE_ADDRESS = '0xYourMarketplaceContractAddress' // replace

export default function MarketplacePage() {
  const [listTokenId, setListTokenId] = useState('')
  const [listPrice, setListPrice] = useState('')
  const [buyTokenId, setBuyTokenId] = useState('')

  // 1) List Card
  const { config: listConfig } = usePrepareContractWrite({
    address: MARKETPLACE_ADDRESS,
    abi: MarketplaceAbi,
    functionName: 'listCard',
    args: [BigInt(listTokenId), BigInt(listPrice)], // convert to BigInt
  })
  const { write: listWrite, isLoading: isListLoading } = useContractWrite(
    listConfig
  )

  // 2) Buy Card
  const { config: buyConfig } = usePrepareContractWrite({
    address: MARKETPLACE_ADDRESS,
    abi: MarketplaceAbi,
    functionName: 'buyCard',
    args: [BigInt(buyTokenId)],
    overrides: {
      value: BigInt(listPrice), // must match price in Wei
    },
  })
  const { write: buyWrite, isLoading: isBuyLoading } = useContractWrite(
    buyConfig
  )

  return (
    <section>
      <h1 className="text-2xl font-bold mb-4">Marketplace</h1>

      <div className="mb-8 p-4 border rounded">
        <h2 className="font-semibold mb-2">List an NFT</h2>
        <div className="flex flex-col space-y-2">
          <label>
            Token ID:
            <input
              type="text"
              className="border p-1 ml-2"
              value={listTokenId}
              onChange={(e) => setListTokenId(e.target.value)}
            />
          </label>
          <label>
            Price (wei):
            <input
              type="text"
              className="border p-1 ml-2"
              value={listPrice}
              onChange={(e) => setListPrice(e.target.value)}
            />
          </label>
        </div>
        <button
          onClick={() => listWrite?.()}
          disabled={!listWrite}
          className="bg-blue-600 text-white px-3 py-1 mt-2 rounded"
        >
          {isListLoading ? 'Listing...' : 'List Card'}
        </button>
      </div>

      <div className="mb-8 p-4 border rounded">
        <h2 className="font-semibold mb-2">Buy an NFT</h2>
        <div className="flex flex-col space-y-2">
          <label>
            Token ID:
            <input
              type="text"
              className="border p-1 ml-2"
              value={buyTokenId}
              onChange={(e) => setBuyTokenId(e.target.value)}
            />
          </label>
        </div>
        <button
          onClick={() => buyWrite?.()}
          disabled={!buyWrite}
          className="bg-green-600 text-white px-3 py-1 mt-2 rounded"
        >
          {isBuyLoading ? 'Buying...' : 'Buy Card'}
        </button>
      </div>
    </section>
  )
}

